code.C:
#include <stdio.h>
int main() {
    int N;
    scanf("%d", &N);
    if (N >= 0 && N < 10) {
        printf("1\n");
    } else if (N >= 10 && N < 100) {
        printf("2\n");
    } else if (N >= 100 && N < 1000) {
        printf("3\n");
    } else {
        printf("More than 3 digits\n");
    }
    return 0;
}

